import React, { useState } from 'react';
import { MapPin, History, BrainCircuit, Navigation, Activity, Loader2 } from 'lucide-react';

function App() {
  const [history, setHistory] = useState("");
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);

  const handlePredict = async () => {
    if (!history) return;
    setLoading(true);
    setError(null);
    
    try {
      const historyArray = history.split(',').map(num => parseInt(num.trim()));
      const response = await fetch('http://localhost:8000/predict', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(historyArray)
      });
      
      if (!response.ok) throw new Error("Backend server is not reachable");
      
      const data = await response.json();
      setResult(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex">
      {/* Sidebar */}
      <div className="w-64 bg-slate-900 text-white p-6 hidden md:block">
        <div className="flex items-center gap-3 mb-10">
          <BrainCircuit className="text-blue-400" size={32} />
          <h1 className="font-bold text-xl tracking-tight">ST-HybridRec</h1>
        </div>
        <nav className="space-y-4">
          <div className="flex items-center gap-3 text-blue-400 bg-slate-800 p-3 rounded-lg">
            <Activity size={20} /> <span>Dashboard</span>
          </div>
          <div className="flex items-center gap-3 text-slate-400 p-3 hover:bg-slate-800 rounded-lg cursor-not-allowed">
            <History size={20} /> <span>Recent Logs</span>
          </div>
        </nav>
      </div>

      {/* Main Content */}
      <main className="flex-1 p-8">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-2xl font-bold text-slate-800">Next POI Prediction</h2>
            <p className="text-slate-500">Spatial-Temporal Hybrid Recommender System</p>
          </div>
          <div className="text-xs font-mono bg-green-100 text-green-700 px-3 py-1 rounded-full border border-green-200">
            System Online: GCN + LSTM
          </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Input Panel */}
          <div className="lg:col-span-1 space-y-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
              <label className="block text-sm font-semibold text-slate-700 mb-2">User Visit History</label>
              <div className="relative">
                <Navigation className="absolute left-3 top-3 text-slate-400" size={18} />
                <input 
                  type="text"
                  value={history} 
                  onChange={(e) => setHistory(e.target.value)}
                  placeholder="e.g. 0, 1, 2"
                  className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                />
              </div>
              <p className="text-[10px] text-slate-400 mt-2 italic">Enter Place IDs separated by commas</p>
              
              <button 
                onClick={handlePredict}
                disabled={loading || !history}
                className="w-full mt-6 bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-xl transition-all flex items-center justify-center gap-2 shadow-lg shadow-blue-200 disabled:bg-slate-300 disabled:shadow-none"
              >
                {loading ? <Loader2 className="animate-spin" /> : "Run Inference"}
              </button>
              {error && <p className="text-red-500 text-xs mt-3 text-center">{error}</p>}
            </div>

            {/* Quick Stats */}
            <div className="bg-gradient-to-br from-blue-600 to-indigo-700 p-6 rounded-2xl text-white shadow-xl">
              <h3 className="font-semibold mb-1">Hybrid Logic</h3>
              <p className="text-blue-100 text-sm opacity-80">Spatial learning via Graph Convolutions combined with Temporal sequence modeling via LSTM.</p>
            </div>
          </div>

          {/* Visualization / Results */}
          <div className="lg:col-span-2 space-y-6">
            {/* Map Placeholder */}
            <div className="bg-slate-200 rounded-2xl h-64 flex flex-col items-center justify-center border-2 border-dashed border-slate-300 text-slate-500 relative overflow-hidden">
               <div className="absolute inset-0 opacity-10" style={{ backgroundImage: 'radial-gradient(#000 1px, transparent 1px)', size: '20px 20px' }}></div>
               <MapPin size={48} className="mb-2 text-slate-400" />
               <p className="font-medium">Spatial Visualization Area</p>
               <p className="text-xs">POI Clusters (GCN Embeddings)</p>
            </div>

            {/* Prediction Card */}
            {/* Change this part in your result card */}
            {/* Inside your Main Content area in App.js */}
           {result && (
            <div className="mt-8 space-y-6 animate-in fade-in slide-in-from-bottom-5 duration-700">
              
              {/* Upper Section: Top Recommendation Focus */}
              <div className="bg-white border border-slate-200 rounded-2xl p-6 shadow-sm flex items-center justify-between">
                <div>
                  <p className="text-xs font-bold text-blue-600 uppercase tracking-widest mb-1">Status</p>
                  <div className="flex items-center gap-2">
                    <div className="h-2 w-2 bg-green-500 rounded-full animate-pulse"></div>
                    <span className="text-slate-700 font-medium">{result.status}</span>
                  </div>
                </div>
                <div className="text-right">
                  <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">Input Trace</p>
                  <code className="bg-slate-100 px-3 py-1 rounded-lg text-slate-600 font-bold">
                    [{result.input_echo.join(", ")}]
                  </code>
                </div>
              </div>

              {/* Middle Section: 3-Column Grid for POIs */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {result.recommendations.map((poi, index) => (
                  <div 
                    key={index} 
                    className={`relative overflow-hidden bg-white border rounded-2xl p-6 transition-all hover:shadow-md ${
                      index === 0 ? 'border-blue-500 ring-1 ring-blue-500' : 'border-slate-200'
                    }`}
                  >
                    {/* Rank Badge */}
                    <div className={`absolute top-0 right-0 px-4 py-1 rounded-bl-xl text-[10px] font-black uppercase ${
                      index === 0 ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-500'
                    }`}>
                      #{index + 1} Recommendation
                    </div>

                    <div className="mt-4">
                      <span className="text-[10px] bg-slate-100 text-slate-500 px-2 py-0.5 rounded-full font-bold uppercase">
                        {poi.category}
                      </span>
                      <h3 className="text-xl font-bold text-slate-800 mt-2 truncate">{poi.name}</h3>
                    </div>

                    {/* Confidence Meter */}
                   <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
  <div 
    className={`h-full transition-all duration-1000 ${index === 0 ? 'bg-blue-600' : 'bg-slate-400'}`}
    // We add 'Math.max(val, 2)' to ensure the bar is always at least 2% visible
    style={{ width: `${Math.max(poi.confidence * 100, 2)}%` }}
  ></div>
</div>
                  </div>
                ))}
              </div>

              {/* Bottom Section: System Logic Information */}
              <div className="bg-blue-50 border border-blue-100 rounded-2xl p-4 flex items-center gap-4 text-blue-700">
                <div className="bg-blue-600 p-2 rounded-lg text-white">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
                  </svg>
                </div>
                <p className="text-sm">
                  Predictions generated using <span className="font-bold">Spatial-Temporal Fusion (ST-Hybrid)</span>. 
                  GCN modeled spatial node relations while LSTM processed the sequence of User Input: [{result.input_echo.join(", ")}].
                </p>
              </div>

            </div>
          )}
          </div>
        </div>
      </main>
    </div>
  );
}

export default App;
